export function stratify(){let id=d=>d.id,parentId=d=>d.parentId;function build(data){const map=new Map(data.map(d=>[id(d),{id:id(d),data:d,parent:null,children:[],depth:0,height:0}]));let root;for(const n of map.values()){const p=parentId(n.data);if(p){n.parent=map.get(p);n.parent?.children.push(n);}else root=n;}function walk(n,d=0){n.depth=d;n.children.sort((a,b)=>a.id.localeCompare(b.id));for(const c of n.children)walk(c,d+1);n.height=n.children.length?1+Math.max(...n.children.map(c=>c.height)):0;return n;}return walk(root)}build.id=f=>{id=f;return build};build.parentId=f=>{parentId=f;return build};return build}
export function tree(){let sep=(a,b)=>a.parent===b.parent?1:2,size=[2*Math.PI,1];function apply(root){const leaves=[];root.eachBefore=n=>{(function w(x){n(x);x.children.forEach(w)})(root)};root.eachBefore(n=>{if(!n.children.length)leaves.push(n)});let i=0;root.eachBefore(n=>{n.x=(i++/(Math.max(1,root.descendants?.().length-1||1)))*size[0];n.y=n.depth*size[1]/Math.max(1,root.height)});return root}apply.separation=f=>{sep=f;return apply};apply.size=s=>{size=s;return apply};return apply}
